-- Kettlebell Deadlift / Trap-Bar Deadlift (kettlebell-deadlift-trap-bar-deadlift)
UPDATE coaching.exercise SET
  name = 'Kettlebell Deadlift / Trap-Bar Deadlift',
  description = 'The athlete sets feet hip-width, braces the trunk, hinges at the hips to grip the load, and stands by driving hips forward while keeping a neutral spine and full foot pressure.',
