  movement_family = 'Hinge / posterior-chain strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'hinge_posterior_chain_strength',
  primary_order_slot = 'deadlift_strength',
  default_sets = 3,
  default_reps = 5,
  default_work_seconds = NULL,
  default_rest_seconds = 120,
  est_seconds_per_set = 45,
  movement_requirements = '{"primary_joint_actions":["hip_hinge","hip_extension","knee_flexion","knee_extension"],"primary_tissues":["glutes","hamstrings","erectors","core"],"breathing_demand":"nasal","balance_demand":"stable","impact_level":0,"prerequisites":[],"setup_requirements":["Clear floor space for hinge and deadlift patterns","Load appropriate to athlete skill and session intent","Stable bench or box for hip thrust and supported patterns","Slider, towel, or Nordic pad setup when hamstring work requires it"]}'::jsonb,
  coaching_execution = '{"movement_description":"Brace trunk, hinge at hips to grip load with neutral spine, drive hips forward to stand without lumbar rounding or early knee shoot.","setup":["Select kettlebell, trap bar, dumbbell, or barbell based on skill.","Feet hip-width, bar or KB between mid-foot.","Confirm pain-free range and supervision for youth.","Use trap bar or KB for beginners before straight barbell."],"execution_steps":["Brace trunk and set neutral spine.","Push hips back and hinge to grip load.","Keep shins relatively vertical on KB/trap bar pulls.","Drive through full foot and extend hips to stand.","Finish tall without hyperextending lumbar spine.","Lower under control and rest fully before the next set."],"breathing_cues":["Big breath and brace before pull — maintain pressure through the rep without losing neutral spine."],"coach_cues":["Hips back.","Chest proud.","Push the floor.","Hips through.","Control the descent."],"athlete_cues":["Brace.","Hinge.","Drive hips.","Stand tall."],"common_faults":["Lumbar rounding at setup or pull.","Bar drifting away from body on barbell pulls.","Squatting the movement instead of hinging.","Hyperextending at lockout.","Rushing reps with short rest.","Using weight beyond clean rep capacity."],"stop_signs":["Sharp low back pain during pull.","Hamstring cramping that breaks form.","Cannot maintain neutral spine under load.","Dizziness or breath-holding valsalva at inappropriate load.","Youth attempting max loads without supervision."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Glute Bridge","Hip Hinge — Skill pattern","Dead Bug","Mini-Band Hip Activation"],"pairs_well_after":["Romanian Deadlift","Hip Thrust / Loaded Glute Bridge","Single-Leg Romanian Deadlift","Farmer Carry"],"good_for_sessions":["capacity_lower_body","hinge_capacity","strength_development"],"avoid_before":["Heavy RDL if deadlift hinge is poor","Max velocity sprints in same session if heavy deadlift block precedes Output"],"avoid_after":[],"do_not_use_when":["Low back pain with loaded hinge","Cannot maintain neutral spine","Using as conditioning circuit","Youth max load without supervision"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["NSCA deadlift coaching progressions","Trap bar deadlift teaching model for athletes"],"internal_notes":["Validator should confirm bilateral deadlift competency before RDL or good morning."]}'::jsonb,
  updated_at = now()
WHERE slug = 'kettlebell-deadlift-trap-bar-deadlift';

