  ('hip-thrust-loaded-glute-bridge', 'Reduce load; monitor pelvic floor symptoms at top range.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('good-morning-light-technical', 'Avoid unless cleared; prefer glute bridge or RDL alternatives.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('hamstring-slider-curl', 'Double-leg only if supine bridging is comfortable.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('nordic-hamstring-eccentric', 'Avoid kneeling loaded eccentrics unless cleared.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('back-extension-hip-extension', 'Reduce ROM; avoid prone loading if uncomfortable.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE NOT EXISTS (
  SELECT 1 FROM coaching.exercise_scaling_profile sp
  WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum'
);

-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('kettlebell-deadlift-trap-bar-deadlift', 'The deadlift pattern loads the entire posterior chain — glutes, hamstrings, and erectors — through a hip hinge with trunk bracing. Kettlebell and trap-bar options reduce technical barrier while building force capacity that supports sprinting, jumping, landing, and lifting.', 'Belongs in deadlift_strength (421) — foundational Capacity bilateral hinge before RDL, good morning, or heavy unilateral patterns.', 'Primary entry in deadlift_strength after Output; before heavy RDL, good morning, or unilateral hinge when bilateral deadlift mechanics and bracing are still developing.', 'Capacity builds strength reserve with intentional load, controlled reps, and full rest — not Prepare warm-up fluff, Output speed work, Fitness circuits, or Control isometric holds. Do not use as a high-rep conditioning drill, max-youth load without supervision, or substitute when athlete cannot maintain neutral spine and hip hinge.', 'Regress to hip hinge drill or elevated trap-bar pull; progress load or barbell only when lumbar control and hip drive stay clean. Hypermobility athletes need active brace — no passive spinal hang.'),
  ('romanian-deadlift', 'The RDL loads hamstrings and glutes through a hip hinge with emphasis on eccentric control and hamstring length under tension. It builds posterior-chain force capacity with less total-system demand than conventional deadlift from the floor when programmed with tempo and full rest.', 'Belongs in hinge_strength (422) — primary Capacity RDL after deadlift competency.', 'hinge_strength after kettlebell or trap-bar deadlift competency; before good morning or single-leg RDL when bilateral RDL mechanics are established.', 'Capacity builds strength reserve with intentional load, controlled reps, and full rest — not Prepare warm-up fluff, Output speed work, Fitness circuits, or Control isometric holds. Do not round the back to chase depth, use as speed pull, or prescribe before deadlift hinge competency.', 'Regress to KB deadlift or dowel hip hinge; shorten ROM before reducing load if hamstring cramping dominates. Use 3-second eccentric before load jumps.'),
  ('single-leg-romanian-deadlift', 'Single-leg RDL increases unilateral hamstring and glute demand while exposing balance and hip stability deficits that bilateral RDL can hide. It builds deceleration-relevant single-leg force capacity for landing, cutting, and sprint mechanics.', 'Belongs in single_leg_hinge (423) — unilateral Capacity hinge after bilateral RDL competency.', 'single_leg_hinge after bilateral RDL competency; before advanced single-leg loading when static hinge control on one leg is established.', 'Capacity builds strength reserve with intentional load, controlled reps, and full rest — not Prepare warm-up fluff, Output speed work, Fitness circuits, or Control isometric holds. Do not prescribe before bilateral RDL control, allow trunk rotation every rep, or use short rest alternating sets as Fitness work.', 'Regress to supported SL RDL or bilateral RDL; add load only when hip stays square and trunk stays stable. Complete all reps one side before switching.'),
  ('hip-thrust-loaded-glute-bridge', 'Hip thrusts isolate hip extension with high glute activation and reduced spinal loading compared with standing hinges. They build horizontal force capacity relevant to sprint acceleration, jumping, and hip extension strength reserve.', 'Belongs in hip_extension_strength (424) — glute-dominant Capacity hip extension after hinge base.', 'hip_extension_strength after deadlift hinge base; pairs with RDL for full posterior-chain Capacity when glute-dominant hip extension is the priority.', 'Capacity builds strength reserve with intentional load, controlled reps, and full rest — not Prepare warm-up fluff, Output speed work, Fitness circuits, or Control isometric holds. Do not hyperextend lumbar at top, use as Fitness burnout reps, or load heavily without supervising barbell setup.', 'Regress to bodyweight or band glute bridge; progress barbell load only when full extension stays glute-driven without lumbar hyperextension. Pad bar for comfort.'),
  ('good-morning-light-technical', 'The good morning trains the posterior chain — erectors, hamstrings, and glutes — through a loaded hip hinge with the load on the upper back. At light technical loads with full rest, it builds hinge awareness and erector capacity when RDL and deadlift patterns are already established.', 'Belongs in hinge_strength (422) — conditional Capacity good morning after RDL competency; moderate intensity ceiling only.', 'hinge_strength after RDL competency; conditional use when athlete needs erector and hamstring hinge strength without heavy spinal compression from floor pulls.', 'Capacity builds strength reserve with intentional load, controlled reps, and full rest — not Prepare warm-up fluff, Output speed work, Fitness circuits, or Control isometric holds. Do not load heavily, prescribe before RDL competency, or use as max-effort powerlifting good morning in youth or general athletic populations.', 'Stay light — regress to dowel or band good morning; shorten ROM before adding load. Discontinue if any low back pain appears.'),
  ('hamstring-slider-curl', 'Slider curls train hamstrings in knee flexion with hips extended — a length-tension position that complements hip-hinge patterns. Eccentric emphasis builds hamstring tissue capacity relevant to sprinting and deceleration without barbell spinal load.', 'Belongs in hamstring_capacity (425) — knee-flexion hamstring Capacity before Nordic eccentric progressions.', 'hamstring_capacity after hinge base; useful accessory before Nordic progressions when athletes need hamstring tissue capacity without high spinal load.', 'Capacity builds strength reserve with intentional load, controlled reps, and full rest — not Prepare warm-up fluff, Output speed work, Fitness circuits, or Control isometric holds. Do not let hips drop every rep, rush eccentrics, or stack high volume before Output sprint work when hamstrings are already sensitive.', 'Regress to partial ROM or double-leg before single-leg; shorten slide distance before adding band. Emphasize slow eccentric before rep progressions.'),
  ('nordic-hamstring-eccentric', 'The Nordic eccentric places maximal demand on hamstrings in lengthened position with high eccentric force — among the strongest evidence-based hamstring resilience tools when dosed conservatively with progression from slider curl and band assist.', 'Belongs in hamstring_eccentric (426) — conditional high-intensity Capacity eccentric after hamstring capacity base.', 'hamstring_eccentric after slider curl or established hamstring capacity; end of hinge cluster or standalone when athlete tolerates high eccentric demand.', 'Capacity builds strength reserve with intentional load, controlled reps, and full rest — not Prepare warm-up fluff, Output speed work, Fitness circuits, or Control isometric holds. Do not prescribe to beginners, stack volume before sprint Output, or use short rest between reps. Not a Control isometric hold.', 'Regress to band-assisted Nordic or slider curl; limit to 2–3 reps with 120s rest. Stop if hamstring cramping or strain symptoms appear.'),
  ('back-extension-hip-extension', 'Back extension and hip extension patterns build posterior-chain capacity — glutes, hamstrings, and erectors — with adjustable load and ROM. When coached for hip-extension bias rather than spinal hyperextension, they complement deadlift and RDL without the same compressive floor-pull demand.', 'Belongs in posterior_chain_capacity (427) — hip-extension-biased Capacity accessory; distinguish from spinal-extension-dominant reps.', 'posterior_chain_capacity at end of hinge cluster or as accessory when athletes need erector and glute capacity without heavy barbell spinal load.', 'Capacity builds strength reserve with intentional load, controlled reps, and full rest — not Prepare warm-up fluff, Output speed work, Fitness circuits, or Control isometric holds. Do not hyperextend lumbar every rep, use as high-rep erector burnout, or confuse hip extension with spinal extension dominance.', 'Regress ROM or use bodyweight floor hip extension; add plate at chest only when hip-extension bias stays clean. Stop if low back pain increases.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Hinge / posterior-chain Capacity cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'capacity_hinge_readiness',
  NULL,
  'Hinge / Posterior-Chain Capacity without stealing Output quality',
  'Posterior-chain Capacity needs intentional load, controlled reps, and full rest — not ballistic swings, warm-up fluff, or conditioning circuits.',
  'Hinge cluster: kettlebell/trap-bar deadlift, RDL, single-leg RDL, hip thrust, good morning, hamstring slider curl, Nordic eccentric, and back extension.',
  'Posterior-chain strength supports sprinting, jumping, landing, deceleration, and tumbling. Poor placement, excessive eccentric volume, or Nordics without progression raise injury risk and reduce Output quality.',
  'Place after Output unless strength-priority; master deadlift/RDL before good morning and Nordics; use slider curl before full Nordics; keep hamstring eccentric volume low before speed days.',
  'Do not program heavy RDL or Nordics before max-velocity sprint, use good mornings for beginners, chase floor range on RDL, or turn hinge work into short-rest Fitness circuits.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
